#include <vector>
#include <queue>
#include <climits>
#include <unordered_map>
#include <utility>

using namespace std;

long long solve(long long n, vector<vector<long long>> edges) {
    // Build the graph: original edges and reversed edges (with 2*w)
    unordered_map<long long, vector<pair<long long, long long>>> graph;
    unordered_map<long long, vector<pair<long long, long long>>> reversed_edges;

    for (const auto& edge : edges) {
        long long u = edge[0], v = edge[1], w = edge[2];
        graph[u].emplace_back(v, w);
        reversed_edges[v].emplace_back(u, 2 * w);
    }

    // Dijkstra's algorithm with state (node, used_flip)
    // dist[node][used_flip] = min distance
    vector<vector<long long>> dist(n, vector<long long>(2, LLONG_MAX));
    dist[0][0] = 0;

    // Priority queue: (distance, node, used_flip)
    priority_queue<tuple<long long, long long, bool>, 
                   vector<tuple<long long, long long, bool>>, 
                   greater<tuple<long long, long long, bool>>> pq;
    pq.emplace(0, 0, false);

    while (!pq.empty()) {
        auto [current_dist, u, used_flip] = pq.top();
        pq.pop();

        if (u == n - 1) {
            return current_dist;
        }

        if (current_dist > dist[u][used_flip]) {
            continue;
        }

        // Traverse original edges
        for (const auto& [v, w] : graph[u]) {
            if (dist[v][used_flip] > current_dist + w) {
                dist[v][used_flip] = current_dist + w;
                pq.emplace(dist[v][used_flip], v, used_flip);
            }
        }

        // If not used flip, try to flip an incoming edge
        if (!used_flip) {
            for (const auto& [v, w] : reversed_edges[u]) {
                if (dist[v][true] > current_dist + w) {
                    dist[v][true] = current_dist + w;
                    pq.emplace(dist[v][true], v, true);
                }
            }
        }
    }

    long long result = min(dist[n-1][0], dist[n-1][1]);
    return result == LLONG_MAX ? -1 : result;
}

