package main

import (
	"container/heap"
)

type Edge struct {
	to   int64
	cost int64
}

type Item struct {
	dist     int64
	node     int64
	usedFlip bool
	index    int
}

type PriorityQueue []*Item

func (pq PriorityQueue) Len() int { return len(pq) }

func (pq PriorityQueue) Less(i, j int) bool {
	return pq[i].dist < pq[j].dist
}

func (pq PriorityQueue) Swap(i, j int) {
	pq[i], pq[j] = pq[j], pq[i]
	pq[i].index = i
	pq[j].index = j
}

func (pq *PriorityQueue) Push(x interface{}) {
	n := len(*pq)
	item := x.(*Item)
	item.index = n
	*pq = append(*pq, item)
}

func (pq *PriorityQueue) Pop() interface{} {
	old := *pq
	n := len(old)
	item := old[n-1]
	old[n-1] = nil
	item.index = -1
	*pq = old[0 : n-1]
	return item
}

func solve(n int64, edges [][]int64) int64 {
	graph := make(map[int64][]Edge)
	reversedEdges := make(map[int64][]Edge)

	for _, edge := range edges {
		u, v, w := edge[0], edge[1], edge[2]
		graph[u] = append(graph[u], Edge{v, w})
		reversedEdges[v] = append(reversedEdges[v], Edge{u, 2 * w})
	}

	dist := make([][]int64, n)
	for i := range dist {
		dist[i] = make([]int64, 2)
		dist[i][0] = 1 << 60
		dist[i][1] = 1 << 60
	}
	dist[0][0] = 0

	pq := make(PriorityQueue, 0)
	heap.Push(&pq, &Item{0, 0, false, 0})

	for pq.Len() > 0 {
		item := heap.Pop(&pq).(*Item)
		currentDist, u, usedFlip := item.dist, item.node, item.usedFlip

		if u == n-1 {
			return currentDist
		}

		if currentDist > dist[u][usedFlipBtoi(usedFlip)] {
			continue
		}

		for _, edge := range graph[u] {
			v, w := edge.to, edge.cost
			if dist[v][usedFlipBtoi(usedFlip)] > currentDist+w {
				dist[v][usedFlipBtoi(usedFlip)] = currentDist + w
				heap.Push(&pq, &Item{dist[v][usedFlipBtoi(usedFlip)], v, usedFlip, 0})
			}
		}

		if !usedFlip {
			for _, edge := range reversedEdges[u] {
				v, w := edge.to, edge.cost
				if dist[v][1] > currentDist+w {
					dist[v][1] = currentDist + w
					heap.Push(&pq, &Item{dist[v][1], v, true, 0})
				}
			}
		}
	}

	result := min(dist[n-1][0], dist[n-1][1])
	if result == 1<<60 {
		return -1
	}
	return result
}

func usedFlipBtoi(b bool) int64 {
	if b {
		return 1
	}
	return 0
}

func min(a, b int64) int64 {
	if a < b {
		return a
	}
	return b
}
